const tests = $input.all();
if (tests.length === 0 || !tests[0].json.id) return [];
return tests.map(t => ({ json: t.json }));

// ============================================
// A/B TESTER v2 - Statistical significance + budget limits + gradual rollout
// ============================================

const testData = $('Check Active Tests').first().json;
const statsRaw = $('Fetch Stats for Test Ads').first().json;
const crmItems = $('Fetch CRM Leads').all().map(i => i.json);
const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

if (!Array.isArray(stats) || !testData.variants) {
  return [{ json: { action: 'SKIP', reason: 'No data' } }];
}

let variants = testData.variants;
if (typeof variants === 'string') {
  try { variants = JSON.parse(variants); } catch(e) { variants = []; }
}

const hoursRunning = Number(testData.hours_running) || 0;
const variantAdIds = variants.map(v => v.ad_id);

// --- CONFIG ---
const MIN_CLICKS_PER_VARIANT = 200;  // Minimum for significance (not 50!)
const MIN_LEADS_PER_VARIANT = 5;
const MIN_HOURS = 48;          // At least 48h (cover different days/hours)
const MAX_HOURS = 168;         // 7 days timeout
const TEST_BUDGET_MULTIPLIER = 10;  // maxCPL * 10 per variant
const CONFIDENCE_LEVEL = 1.96; // 95% confidence (z-score)

// CRM map
const crmMap = {};
crmItems.forEach(c => {
  const adId = Number(c.ad_id);
  if (adId) crmMap[adId] = {
    leads: Number(c.total_leads) || 0,
    deps: Number(c.depositors) || 0,
    rev: Number(c.crm_revenue) || 0
  };
});

// Get stats for test variants
const variantStats = stats
  .filter(s => variantAdIds.includes(s.ad_id))
  .map(s => {
    const adId = s.ad_id;
    const spend = Number(s.money) || 0;
    const clicks = Number(s.clicks_count) || 0;
    const shows = Number(s.shows_count) || 0;
    const ctr = shows > 0 ? (clicks / shows * 100) : 0;
    const crm = crmMap[adId] || { leads: 0, deps: 0, rev: 0 };
    const cpl = crm.leads > 0 ? spend / crm.leads : (spend > 0 ? Infinity : 0);
    const roi = spend > 0 ? ((crm.rev - spend) / spend * 100) : 0;
    return {
      ad_id: adId,
      clicks, shows, spend,
      ctr, roi, cpl,
      leads: crm.leads,
      deps: crm.deps,
      revenue: crm.rev,
      cr: clicks > 0 ? (crm.leads / clicks * 100) : 0,  // Conversion rate
      has_enough_clicks: clicks >= MIN_CLICKS_PER_VARIANT,
      has_enough_leads: crm.leads >= MIN_LEADS_PER_VARIANT
    };
  });

// Check timeout
if (hoursRunning > MAX_HOURS) {
  // Force decide with whatever data we have
  const sorted = [...variantStats].sort((a, b) => {
    if (a.cpl !== Infinity && b.cpl !== Infinity && a.cpl !== b.cpl) return a.cpl - b.cpl;
    return b.ctr - a.ctr;
  });
  return [{
    json: {
      action: 'FORCE_DECIDE',
      test_id: testData.id,
      test_name: testData.test_name,
      reason: `Timeout: ${hoursRunning.toFixed(0)}h > ${MAX_HOURS}h max`,
      winner: sorted[0] || null,
      losers: sorted.slice(1).map(l => l.ad_id),
      all_variants: sorted,
      gradual_rollout: true
    }
  }];
}

// Check if minimum time has passed
if (hoursRunning < MIN_HOURS) {
  return [{ json: {
    action: 'WAITING',
    test_id: testData.id,
    reason: `Need ${MIN_HOURS}h min, only ${hoursRunning.toFixed(1)}h elapsed`,
    variants: variantStats
  }}];
}

// Check data sufficiency
const allHaveClicks = variantStats.every(v => v.has_enough_clicks);
const anyHaveLeads = variantStats.some(v => v.has_enough_leads);

if (!allHaveClicks && !anyHaveLeads) {
  return [{ json: {
    action: 'WAITING',
    test_id: testData.id,
    reason: `Not enough data: need ${MIN_CLICKS_PER_VARIANT} clicks or ${MIN_LEADS_PER_VARIANT} leads per variant`,
    variants: variantStats
  }}];
}

// --- STATISTICAL SIGNIFICANCE TEST (Z-test for proportions) ---
// Compare each pair of variants on conversion rate (CR)
let isSignificant = false;
let significanceNote = '';

if (variantStats.length >= 2 && variantStats[0].clicks > 0 && variantStats[1].clicks > 0) {
  const v1 = variantStats[0];
  const v2 = variantStats[1];

  const p1 = v1.cr / 100; // Convert % to proportion
  const p2 = v2.cr / 100;
  const n1 = v1.clicks;
  const n2 = v2.clicks;

  if (n1 > 0 && n2 > 0) {
    const pCombined = (p1 * n1 + p2 * n2) / (n1 + n2);
    const denominator = Math.sqrt(pCombined * (1 - pCombined) * (1/n1 + 1/n2));

    if (denominator > 0) {
      const zScore = Math.abs(p1 - p2) / denominator;
      isSignificant = zScore >= CONFIDENCE_LEVEL;
      significanceNote = `Z-score: ${zScore.toFixed(2)} (need ${CONFIDENCE_LEVEL} for 95% confidence) - ${isSignificant ? 'SIGNIFICANT' : 'NOT significant'}`;
    }
  }
}

// If not statistically significant and we have time, keep testing
if (!isSignificant && hoursRunning < MAX_HOURS * 0.8) {
  return [{ json: {
    action: 'WAITING',
    test_id: testData.id,
    reason: `Not statistically significant yet. ${significanceNote}`,
    variants: variantStats
  }}];
}

// --- DECIDE WINNER ---
// Priority: CPL (lower=better) > CR (higher=better) > CTR (higher=better)
const sorted = [...variantStats].sort((a, b) => {
  // First: compare by CPL (lower is better), Infinity = worst
  if (a.leads > 0 && b.leads > 0) {
    if (Math.abs(a.cpl - b.cpl) > 5) return a.cpl - b.cpl;
  } else if (a.leads > 0) return -1;
  else if (b.leads > 0) return 1;

  // Second: CR
  if (Math.abs(a.cr - b.cr) > 0.1) return b.cr - a.cr;

  // Third: CTR
  return b.ctr - a.ctr;
});

const winner = sorted[0];
const losers = sorted.slice(1);

return [{
  json: {
    action: 'DECIDE',
    test_id: testData.id,
    test_name: testData.test_name,
    winner: winner,
    losers: losers.map(l => l.ad_id),
    all_variants: sorted,
    significance: significanceNote,
    is_significant: isSignificant,
    hours_running: Math.round(hoursRunning),
    gradual_rollout: true  // Always do gradual rollout
  }
}];

